
.magnetic-btn {
  position: relative;
  overflow: hidden;
  transition: transform 0.15s ease-out;
  cursor: pointer;
  border: none;
  background: transparent;
  padding: 0;

  &:focus {
    outline: none;
  }
}

.content {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  transition: transform 0.15s ease-out;
}
