
.shattered-glass {
  position: absolute;
  inset: 0;
  pointer-events: none;
  z-index: 0;
  overflow: hidden;
}

.crack {
  position: absolute;
  opacity: 0.7;

  svg {
    width: 100%;
    height: 100%;
  }
}

.top-left {
  top: 0;
  left: 0;
  width: 40%;
  height: 40%;
}

.bottom-right {
  bottom: 0;
  right: 0;
  width: 50%;
  height: 50%;
}

.top-right {
  top: 0;
  right: 0;
  width: 30%;
  height: 40%;
  opacity: 0.6;
}

.bottom-left {
  bottom: 0;
  left: 0;
  width: 35%;
  height: 35%;
  opacity: 0.6;
}

.glitch-text {
  position: absolute;
  font-family: 'Courier New', monospace;
  font-size: 10px;
  color: rgba(6, 182, 212, 0.6);
  animation: glitch 4s infinite alternate;
  transform: rotate(15deg);
  white-space: nowrap;

  &.delayed {
    animation-delay: 1.5s;
    color: rgba(168, 85, 247, 0.5);
    transform: rotate(-25deg);
  }

  &.pulse {
    animation: glitch 4s infinite alternate, pulse-text 2s ease-in-out infinite;
    color: rgba(6, 182, 212, 0.4);
    transform: rotate(5deg);
  }

  &.small {
    font-size: 8px;
    color: rgba(255, 255, 255, 0.2);
    transform: rotate(45deg);
  }
}

.symbol {
  position: absolute;
  font-family: serif;
  font-size: 14px;
  color: rgba(255, 255, 255, 0.3);
  transform: rotate(45deg);

  &.cyan {
    color: rgba(6, 182, 212, 0.3);
    transform: rotate(-20deg);
  }

  &.purple {
    color: rgba(168, 85, 247, 0.3);
    transform: rotate(25deg);
  }
}

@keyframes glitch {
  0%, 100% { opacity: 1; transform: translate(0) rotate(var(--rotation, 15deg)); }
  10% { opacity: 0.4; transform: translate(-2px, 1px) rotate(var(--rotation, 15deg)); }
  20% { opacity: 1; transform: translate(2px, -1px) rotate(var(--rotation, 15deg)); }
  30% { opacity: 0.4; transform: translate(-1px, -2px) rotate(var(--rotation, 15deg)); }
  40% { opacity: 1; transform: translate(1px, 2px) rotate(var(--rotation, 15deg)); }
  50% { opacity: 0.8; transform: translate(0) rotate(var(--rotation, 15deg)); }
}

@keyframes pulse-text {
  0%, 100% { opacity: 0.4; }
  50% { opacity: 0.7; }
}
