
.terminal-snippets {
  position: absolute;
  left: 16px;
  top: 25%;
  bottom: 25%;
  width: 200px;
  overflow: hidden;
  pointer-events: none;
  opacity: 0.05;
  font-family: 'Courier New', monospace;
  font-size: 10px;
  color: #06b6d4;
  line-height: 1.6;
  z-index: 1;
}

.scroll-content {
  animation: scroll-terminal 20s linear infinite;
}

@keyframes scroll-terminal {
  0% { transform: translateY(0); }
  100% { transform: translateY(-33.33%); }
}

.snippet {
  margin-bottom: 8px;
  white-space: nowrap;
}
